func _checkNotDoubleLaunch() -> bool:

    var file_name: String = _getSaveFileName(SAVEINDEX_LOCK____)

    if ( !FileAccess.file_exists(file_name)):
        print("OK (Lock File is Not Found)")
        return false

    print("LOCK FILE!!")
    var lock_data: Dictionary = {}
    var f: FileAccess = FileAccess.open(file_name, FileAccess.READ)
    var s: String = f.get_as_text()

    lock_data = str_to_var(s)

    f.close()

    if ( !lock_data.has(LOCKDATA_TIME___)):
        print("OK (Timestamp is Not Found)")
        return false

    var time_pre: float = float(lock_data[LOCKDATA_TIME___])
    var time_now: float = _getNowTime()
    var time_def: float = (time_now - time_pre)
    print_debug("time (pre) : %s" % time_pre)
    print_debug("time (now) : %s" % time_now)
    print_debug("time (def) : %s" % time_def)

    if (absf(time_def) > LOCKTIME_LIM):
        print("OK (Lock File is Old)")
        return false
    return true

