func _readConfigFile() -> void :

    var list_csv: Array[PackedStringArray] = []

    var file_csv: FileAccess = FileAccess.open("res://locate.data", FileAccess.READ)
    if file_csv == null:
        print_debug("Error: Cannot open res://locate.data. Skipping translation load.")
        return

    while (file_csv.get_position() < file_csv.get_length()):
        list_csv.append(file_csv.get_csv_line())

    file_csv.close()
    var locales: PackedStringArray = list_csv[0]
    for locale_idx: int in len(locales) - 1:
        var translation: Translation = Translation.new()
        translation.locale = locales[locale_idx + 1]
        var message_lines: Array = list_csv.slice(1)
        for message_line_idx: int in len(message_lines):
            var key: String = message_lines[message_line_idx][0] as String
            var translated: String = message_lines[message_line_idx][locale_idx + 1].c_unescape() as String
            translation.add_message(key, translated)
        TranslationServer.add_translation(translation)
    TranslationServer.set_locale("ja")








