           (checkEjacModeViewOnly() || checkEjacModePlaying())
        && !checkElectMeterMax()):
        _addElectMeter(ELECTMETER_TIME)
    elif (checkEjacModeElect()):
        _setElectMeter(ELECTMETER_MAX)

    if (checkEjacModeElect()):
