func _convMessage(inMsg: String) -> String:
    var result: String = inMsg

    result = _convMessageColor(result)

    result = result.replace("[W_NN]", _getWord(WORD_OTHER___NONE__3))
    result = result.replace("[W_G1]", _getWord(WORD_NAME____GIRL1__))
    result = result.replace("[W_G2]", _getWord(WORD_NAME____GIRL2__))
    result = result.replace("[W_G3]", _getWord(WORD_NAME____GIRL3__))
    result = result.replace("[W_G4]", _getWord(WORD_NAME____GIRL4__))

    return result

func _convMessageColor(inMsg: String) -> String:
    var result: String = inMsg
    result = result.replace("[N_G1]", "[C_G]『[W_G1]』[/C]")
    result = result.replace("[N_G2]", "[C_G]『[W_G2]』[/C]")
    result = result.replace("[N_G3]", "[C_G]『[W_G3]』[/C]")
    result = result.replace("[N_G4]", "[C_G]『[W_G4]』[/C]")

    result = result.replace("[C_W]", "[color=#FFFFFF]")
    result = result.replace("[C_Y]", "[color=#FFFF66]")
    result = result.replace("[C_D]", "[color=#FF0000]")
    result = result.replace("[C_G]", "[color=#00FF00]")
    result = result.replace("[C_P]", "[color=#FF66FF]")
    result = result.replace("[C_G1]", "[color=#FF9682]")
    result = result.replace("[C_G2]", "[color=#FFFF00]")
    result = result.replace("[C_G3]", "[color=#66FFFF]")
    result = result.replace("[C_G4]", "[color=#FF6666]")
    result = result.replace("[C_DGIRL]", "[color=#EE7800]")
    result = result.replace("[/C]", "[/color]")


    return result



